    let currentLayer = null;

    async function loadTrips(projectName) {
        document.getElementById('trip-list').innerHTML = '<p style="text-align: center; color: var(--text-muted); margin-top: 40px;">Fetching your mapped trips...</p>';
        try {
            const response = await fetch(`/api/trips/${projectName}`);
            const trips = await response.json();

            if (trips.length === 0) {
                document.getElementById('trip-list').innerHTML = '<p style="text-align: center; color: var(--text-muted); margin-top: 40px;">No valid driving trips found in this file.</p>';
                return;
            }

            renderSidebar(trips);
            drawMap(trips);
        } catch (err) {
            document.getElementById('trip-list').innerHTML = `<p style="color: red;">Error loading trips: ${err}</p>`;
        }
    }

    function renderSidebar(trips) {
        const container = document.getElementById('trip-list');
        container.innerHTML = ''; // Clear the loading text

        let totalMiles = 0;

        trips.forEach(trip => {
            totalMiles += trip.distance_miles;
            const card = document.createElement('div');
            card.className = 'trip-card';

            const startTime = new Date(trip.start_time).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
            const endTime = new Date(trip.end_time).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});

            card.innerHTML = `
                <div class="trip-header">
                    <span>${trip.date} | ${startTime} - ${endTime}</span>
                </div>
                <div class="trip-distance">${trip.distance_miles.toFixed(1)} mi</div>
                <div class="btn-group">
                    <button class="btn-commute" onclick="alert('Database tagging coming soon!')">🚗 Commute</button>
                    <button class="btn-work" onclick="alert('Database tagging coming soon!')">💼 Work</button>
                    <button class="btn-personal" onclick="alert('Database tagging coming soon!')">🏠 Personal</button>
                </div>
            `;
            container.appendChild(card);
        });

        document.getElementById('stat-total').innerText = totalMiles.toFixed(1);
    }

    function drawMap(trips) {
        if (currentLayer) map.removeLayer(currentLayer);
        const markers = [];
        const polylinePoints = [];

        trips.forEach(trip => {
            polylinePoints.push([trip.start_lat, trip.start_lng]);
            polylinePoints.push([trip.end_lat, trip.end_lng]);

            // Add a yellow marker for every stop
            const marker = L.circleMarker([trip.start_lat, trip.start_lng], {
                radius: 5, fillColor: "#f59e0b", color: "#000", weight: 1, opacity: 1, fillOpacity: 1
            }).bindPopup(`<b>${trip.date}</b><br>Distance: ${trip.distance_miles.toFixed(1)} mi`);
            markers.push(marker);
        });

        // Draw the connecting route line in blue
        const line = L.polyline(polylinePoints, {color: '#3b82f6', weight: 2, opacity: 0.5});
        currentLayer = L.layerGroup([...markers, line]).addTo(map);

        // Auto-zoom the map to fit all your driving routes
        if (polylinePoints.length > 0) {
            map.fitBounds(line.getBounds());
        }
    }
